import{_ as a,c as n,a as e,o as l}from"./app-BmoKH6GE.js";const o="/mother-docs/assets/mother-gui1-Br3dJngZ.png",i="/mother-docs/assets/mother-gui2-BaURKZKQ.png",t="/mother-docs/assets/mother-gui3-DfbmpfTo.png",p={};function r(c,s){return l(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="mother-1-1-release" tabindex="-1"><a class="header-anchor" href="#mother-1-1-release"><span>Mother 1.1 Release</span></a></h1><p>Hi guys, I&#39;m happy to invite you to the official Mother beta testing group! Your support was incredibly important in the development of Mother OS and Mother Core, and after about 6 months of ongoing feedback and testing, v1.1 of Mother OS and Mother Core are nearly ready. I am hoping to release immediately after the SE 1.209 release to take advantage of the hype!</p><p>--</p><p>The Version 1.1 release will come with improvements (and intros) to the following tools. I have included documentation covering changes (and areas to test below).</p><ol><li><a href="#mother-os-v11">Mother OS (v1.1)</a></li><li><a href="#mother-core-v11">Mother Core (v1.1)</a></li><li><a href="#mother-autopilot-system---maps-v01">Mother Autopilot System - MAPS (v0.1)</a></li><li><a href="#mother-gui-v01">Mother GUI (v0.1)</a></li><li><a href="#mother-cli-v103">Mother CLI (v1.0.3)</a></li><li><a href="#mother-dev-tools-v02">Mother Dev Tools (v0.2)</a></li></ol><p>Please feel free to provide feedback here with code examples and screenshots/videos if possible! All scripts have been tested and are working in the upcoming Space Engineers 1.209 update 🙂</p><h2 id="mother-os-v1-1" tabindex="-1"><a class="header-anchor" href="#mother-os-v1-1"><span>Mother OS (v1.1)</span></a></h2><p>IMPORTANT - Mother OS no longer supports flight planning or autopilot features. These have been moved to the <a href="#mother-autopilot-system---maps-v01">Mother Autopilot System</a></p><h3 id="command-sharing" tabindex="-1"><a class="header-anchor" href="#command-sharing"><span>Command Sharing</span></a></h3><p>Mother OS, MAPS, and Mother GUI will all interoperate seamlessly when you load them. GUI can easily call a command registered on another script running Mother Core. I have tried extremely hard to make this next generation of Mother Core scripts operate without requiring any additional work from the player.</p><p><strong>Example</strong></p><p>We can call a command registered in MOS from Mother GUI, and vice-versa.</p><p>MOS Programmable Block</p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#D4D4D4;">[commands]</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">LightsOn</span><span style="color:#D4D4D4;">=block/on Lights</span><span style="color:#6A9955;">; light/color Lights white;</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><p>Mother GUI Programmable Block</p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#D4D4D4;">[commands]</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">ActivateLights</span><span style="color:#D4D4D4;">=LightsOn</span><span style="color:#6A9955;">;</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h3 id="merge-block-mechanical-block-attachment-support" tabindex="-1"><a class="header-anchor" href="#merge-block-mechanical-block-attachment-support"><span>Merge Block &amp; Mechanical Block Attachment Support</span></a></h3><p>After a very long wait, Mother Core now natively supports connecting and disconnecting from other grids using merge blocks and mechanical connections (piston, rotor, hinge). With some of your help, the Block Catalogue has evolved to be an extremely responsive system that watches your grid for changes and updates the relevant configurations without breaking a sweat. Mother OS is now running buttery smooth on every grid she&#39;s been tested on - big and small.</p><h3 id="variables" tabindex="-1"><a class="header-anchor" href="#variables"><span>Variables</span></a></h3><p>You have two options for variables - global which is defined in the custom data <code>variables</code> section, or inline variables which can be used to dynamically pass in variables during command execution.</p><p><strong>Example</strong></p><p>Global Variable in Programmable Block Custom Data</p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#D4D4D4;">[variables]</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">PLAYER</span><span style="color:#D4D4D4;">=Dave</span></span></span>
<span class="line"><span class="line"></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">[commands]</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">greeting</span><span style="color:#D4D4D4;">=screen/print BedroomDisplay </span><span style="color:#CE9178;">&quot;Good morning, $PLAYER&quot;</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><p><strong>Example - Execute in Terminal</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-bash"><code><span class="line"><span class="line"><span style="color:#DCDCAA;">greeting</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;"># =&gt; Good morning, Dave!</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><p>Inline Variables in terminal, or custom commands:</p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#D4D4D4;">[commands]</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">greeting</span><span style="color:#D4D4D4;">=screen/print AirlockScreen </span><span style="color:#CE9178;">&quot;Hello, {{player:Space Engineer}}!&quot;</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><p><strong>Example - Execute in Terminal</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-bash"><code><span class="line"><span class="line"><span style="color:#6A9955;"># without parameter</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">greeting</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;"># =&gt; Hello, Space Engineer!</span></span></span>
<span class="line"><span class="line"></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;"># with parameter</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">greeting</span><span style="color:#D4D4D4;"> </span><span style="color:#569CD6;">--player=Agentluke</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;"># =&gt; Hello, Agentluke!</span></span></span>
<span class="line"><span class="line"></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;"># with spaces</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">greeting</span><span style="color:#D4D4D4;"> </span><span style="color:#569CD6;">--player=</span><span style="color:#CE9178;">&quot;Ellen Ripley&quot;</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;"># =&gt; Hello, Ellen Ripley!</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h3 id="parallel-command-execution" tabindex="-1"><a class="header-anchor" href="#parallel-command-execution"><span><em>Parallel</em> Command Execution</span></a></h3><p>You can now run commands in a pseudo-parallel fashion, meaning you can, for example, trigger several large hangar doors to open simultaneously vs. having them open in sequence. I have found this most useful when you have several complex commands that need to run independently. By encapsulating commands and routines in curly braces <code>{}</code>, we can tell the Command Bus to execute them separately (in parallel), vs. in series.</p><p><strong>Example - Programmable Block Custom Data</strong></p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#D4D4D4;">[commands]</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; wait, then open HangarDoor1, then open HangarDoor2</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">openHangarDoors</span><span style="color:#D4D4D4;">=wait 5</span><span style="color:#6A9955;">; door/open HangarDoor1; door/open HangarDoor2;</span></span></span>
<span class="line"><span class="line"></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; wait, then open both hangar doors at the same time</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">openHangarDoors</span><span style="color:#D4D4D4;">=wait 5</span><span style="color:#6A9955;">; {door/open HangarDoor1} {door/open HangarDoor2}</span></span></span>
<span class="line"><span class="line"></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; run a stored command in parallel with an inline command</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">greeting</span><span style="color:#D4D4D4;">=screen/print </span><span style="color:#CE9178;">&quot;HangarScreen&quot;</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">&quot;Welcome to the hangar!&quot;</span><span style="color:#6A9955;">;</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">openHangarDoors</span><span style="color:#D4D4D4;">=wait 5</span><span style="color:#6A9955;">; {greeting} {door/open HangarDoor1}</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h3 id="new-improved-commands" tabindex="-1"><a class="header-anchor" href="#new-improved-commands"><span>New/Improved Commands</span></a></h3><h4 id="light-color" tabindex="-1"><a class="header-anchor" href="#light-color"><span>light/color</span></a></h4><p>Light color now supports hexadecimal, rgb, and some shortcut names for the most common colors.</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-bash"><code><span class="line"><span class="line"><span style="color:#6A9955;"># name</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">light/color</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">Light1</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">red</span><span style="color:#D4D4D4;">;</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;"># hexadecimal</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">light/color</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">Light1</span><span style="color:#D4D4D4;"> </span><span style="color:#6A9955;">#FF0000;</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;"># RGB</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">light/color</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">Light1</span><span style="color:#D4D4D4;"> </span><span style="color:#B5CEA8;">255</span><span style="color:#CE9178;">,0,0</span><span style="color:#D4D4D4;">;</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h4 id="piston-distance-rotor-rotate-hinge-rotate" tabindex="-1"><a class="header-anchor" href="#piston-distance-rotor-rotate-hinge-rotate"><span>piston/distance, rotor/rotate, hinge/rotate</span></a></h4><p>All three &quot;set into motion&quot; mechanical block commands now support a <code>--share</code> option which allows the player to distribute movement across a group of blocks. The examples show how we could either move a single block to position, or use the shared motion of several blocks to achieve the same outcome. This is a great QoL improvement for the more complex extension and retraction mechanisms some of you are building.</p><p><strong>Example - Piston Distance</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-bash"><code><span class="line"><span class="line"><span style="color:#6A9955;"># Each piston extends to 10m</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">piston/distance</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">PistonGroup</span><span style="color:#D4D4D4;"> </span><span style="color:#B5CEA8;">10</span></span></span>
<span class="line"><span class="line"></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;"># Total 10m shared between pistons (5m each for 2 pistons)</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">piston/distance</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">PistonGroup</span><span style="color:#D4D4D4;"> </span><span style="color:#B5CEA8;">10</span><span style="color:#D4D4D4;"> </span><span style="color:#569CD6;">--share</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><p><strong>Example - Rotor Angle</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-bash"><code><span class="line"><span class="line"><span style="color:#6A9955;"># Each rotor rotates to 90°</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">rotor/rotate</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">RotorGroup</span><span style="color:#D4D4D4;"> </span><span style="color:#B5CEA8;">90</span></span></span>
<span class="line"><span class="line"></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;"># Total 90° shared between rotors (45° each for 2 rotors)</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">rotor/rotate</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">RotorGroup</span><span style="color:#D4D4D4;"> </span><span style="color:#B5CEA8;">90</span><span style="color:#D4D4D4;"> </span><span style="color:#569CD6;">--share</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><p><strong>Example - Hinge Angle</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-bash"><code><span class="line"><span class="line"><span style="color:#6A9955;"># Each hinge rotates to 60°</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">hinge/rotate</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">HingeGroup</span><span style="color:#D4D4D4;"> </span><span style="color:#B5CEA8;">60</span></span></span>
<span class="line"><span class="line"></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;"># Total 60° shared between hinges (30° each for 2 hinges)</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">hinge/rotate</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">HingeGroup</span><span style="color:#D4D4D4;"> </span><span style="color:#B5CEA8;">60</span><span style="color:#D4D4D4;"> </span><span style="color:#569CD6;">--share</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h4 id="piston-attach-piston-detach-rotor-attach-rotor-detach-hinge-attach-hinge-detach" tabindex="-1"><a class="header-anchor" href="#piston-attach-piston-detach-rotor-attach-rotor-detach-hinge-attach-hinge-detach"><span><code>piston/attach</code>, <code>piston/detach</code>, <code>rotor/attach</code>, <code>rotor/detach</code>, <code>hinge/attach</code>, <code>hinge/detach</code></span></a></h4><p>With Mother now supporting grid construct changes, it was natural to introduce commands to attach and detach mechanical blocks to take advantage of this new capability. They work exactly as you&#39;d expect:</p><p><strong>Example</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-bash"><code><span class="line"><span class="line"><span style="color:#6A9955;"># Detach rotor head</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">rotor/detach</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">LandingGearLock</span></span></span>
<span class="line"><span class="line"></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;"># Attach rotor head</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">rotor/attach</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">LandingGearLock</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h4 id="piston-ulimit-piston-llimit-rotor-ulimit-rotor-llimit-hinge-ulimit-hinge-llimit" tabindex="-1"><a class="header-anchor" href="#piston-ulimit-piston-llimit-rotor-ulimit-rotor-llimit-hinge-ulimit-hinge-llimit"><span><code>piston/ulimit</code>, <code>piston/llimit</code>, <code>rotor/ulimit</code>, <code>rotor/llimit</code>, <code>hinge/ulimit</code>, <code>hinge/llimit</code></span></a></h4><p>Mechanical blocks now expose explicit upper and lower limit commands so players can clamp motion. This is useful when you want to reconfigure safe travel bounds without manually opening the terminal for each block.</p><p><strong>Example - Piston Limits</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-bash"><code><span class="line"><span class="line"><span style="color:#6A9955;"># Clamp a piston group between 1.5m and 7.5m</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">piston/llimit</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">PistonGroup</span><span style="color:#D4D4D4;"> </span><span style="color:#B5CEA8;">1.5</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">piston/ulimit</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">PistonGroup</span><span style="color:#D4D4D4;"> </span><span style="color:#B5CEA8;">7.5</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><p><strong>Example - Rotor Limits</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-bash"><code><span class="line"><span class="line"><span style="color:#6A9955;"># Restrict a rotor to a forward scanning arc</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">rotor/llimit</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">TurretRotor</span><span style="color:#D4D4D4;"> </span><span style="color:#569CD6;">-45</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">rotor/ulimit</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">TurretRotor</span><span style="color:#D4D4D4;"> </span><span style="color:#B5CEA8;">120</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><p><strong>Example - Hinge Limits</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-bash"><code><span class="line"><span class="line"><span style="color:#6A9955;"># Limit a landing hinge travel range</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">hinge/llimit</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">LandingGearHinge</span><span style="color:#D4D4D4;"> </span><span style="color:#569CD6;">-15</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">hinge/ulimit</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">LandingGearHinge</span><span style="color:#D4D4D4;"> </span><span style="color:#B5CEA8;">45</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h4 id="wheel-height" tabindex="-1"><a class="header-anchor" href="#wheel-height"><span><code>wheel/height</code></span></a></h4><ul><li>Add <code>wheel/height</code> command to set the height offset of wheel suspensions. Supports <code>--add</code> and <code>--sub</code> flags for incremental adjustments.</li></ul><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#6A9955;">; absolute</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">wheel/height MainWheels 0.5</span><span style="color:#6A9955;">;</span></span></span>
<span class="line"><span class="line"></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; incremental</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">wheel/height MainWheels 0.1 --add</span><span style="color:#6A9955;">;</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h4 id="wheel-power" tabindex="-1"><a class="header-anchor" href="#wheel-power"><span><code>wheel/power</code></span></a></h4><p>Set the power of a wheel or group of wheels as a percentage. Power controls how much force the wheel applies when driving.</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-bash"><code><span class="line"><span class="line"><span style="color:#6A9955;"># set power to 50%</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">wheel/power</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">&quot;Backup Wheels&quot;</span><span style="color:#D4D4D4;"> </span><span style="color:#B5CEA8;">50</span><span style="color:#D4D4D4;">;</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h4 id="wheel-friction" tabindex="-1"><a class="header-anchor" href="#wheel-friction"><span><code>wheel/friction</code></span></a></h4><p>Set the friction of a wheel or group of wheels as a percentage. Friction affects how much grip the wheel has on surfaces.</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-bash"><code><span class="line"><span class="line"><span style="color:#6A9955;"># set friction to 75%</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">wheel/friction</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">&quot;All Wheels&quot;</span><span style="color:#D4D4D4;"> </span><span style="color:#B5CEA8;">75</span><span style="color:#D4D4D4;">;</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h4 id="wheel-strength" tabindex="-1"><a class="header-anchor" href="#wheel-strength"><span><code>wheel/strength</code></span></a></h4><p>Set the strength of a wheel or group of wheels as a percentage. Strength controls the suspension stiffness.</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-bash"><code><span class="line"><span class="line"><span style="color:#6A9955;"># set to max strength (100%)</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">wheel/strength</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">&quot;All Wheels&quot;</span><span style="color:#D4D4D4;"> </span><span style="color:#B5CEA8;">100</span><span style="color:#D4D4D4;">;</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h4 id="block-rename" tabindex="-1"><a class="header-anchor" href="#block-rename"><span><code>block/rename</code></span></a></h4><p>Rename a block by setting its custom name.</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-bash"><code><span class="line"><span class="line"><span style="color:#6A9955;"># Piston 1 -&gt; DrillPiston</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">block/rename</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">&quot;Piston 1&quot;</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">DrillPiston</span><span style="color:#D4D4D4;">;</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h4 id="rename" tabindex="-1"><a class="header-anchor" href="#rename"><span><code>rename</code></span></a></h4><p>This allows you to rename your current grid. This is extremely useful when printing unique variants of a grid, so it also supports a <code>--unique</code> option.</p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#6A9955;">; rename the current grid (we just provide the new name - easy peasy)</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">rename Mothership</span></span></span>
<span class="line"><span class="line"></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; rename and ensure unique</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">rename Missile --unique</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; CustomName = Missile-12345</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h4 id="var-set" tabindex="-1"><a class="header-anchor" href="#var-set"><span><code>var/set</code></span></a></h4><p>Dynamically sets a variable from the terminal or from within a command routine. Useful for updating values that are shared across commands without editing Custom Data.</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-bash"><code><span class="line"><span class="line"><span style="color:#DCDCAA;">var/set</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">PLAYER</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">Agentluke</span><span style="color:#D4D4D4;">;</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">greeting</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;"># =&gt; Good morning, Agentluke!</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h3 id="new-hooks" tabindex="-1"><a class="header-anchor" href="#new-hooks"><span>New Hooks</span></a></h3><h4 id="onboot-hook" tabindex="-1"><a class="header-anchor" href="#onboot-hook"><span><code>onBoot</code> Hook</span></a></h4><p>Define on the programmable block itself to run commands after a successful boot cycle.</p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#D4D4D4;">[hooks]</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">onBoot</span><span style="color:#D4D4D4;">=screen/print StatusLCD </span><span style="color:#CE9178;">&quot;Mother Online&quot;</span><span style="color:#6A9955;">;</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h3 id="new-hooks-1" tabindex="-1"><a class="header-anchor" href="#new-hooks-1"><span>New Hooks</span></a></h3><h4 id="onmerge-onunmerge-onattach-ondetach" tabindex="-1"><a class="header-anchor" href="#onmerge-onunmerge-onattach-ondetach"><span><code>onMerge</code>, <code>onUnmerge</code>, <code>onAttach</code>, <code>onDetach</code></span></a></h4><p>These hooks can be used on the respective merge or mechanical block to take advantage of attach and detach events.</p><h3 id="manually-setting-mother-grid-name" tabindex="-1"><a class="header-anchor" href="#manually-setting-mother-grid-name"><span>Manually Setting Mother grid name</span></a></h3><p>Players can now override the instance name via configuration. This allows a programmable block to declare its own name rather than deferring to the grid&#39;s custom name. This is useful for subgrids with unusual names that should act as the &quot;main grid&quot; from Mother&#39;s perspective.</p><p><strong>Example - Programmable Block Custom Data</strong></p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#D4D4D4;">[general]</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">name</span><span style="color:#D4D4D4;">=</span><span style="color:#CE9178;">&quot;Slave 2&quot;</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h2 id="mother-core-v1-1" tabindex="-1"><a class="header-anchor" href="#mother-core-v1-1"><span>Mother Core (v1.1)</span></a></h2><h3 id="remove-dependency-on-remote-control-block" tabindex="-1"><a class="header-anchor" href="#remove-dependency-on-remote-control-block"><span>Remove dependency on Remote Control Block</span></a></h3><p>The Remote Control block is no longer a requirement for Mother Core to operate. Remote control specific logic has been migrated to MAPS. Ship speed, gravity and mass are now determined from the first available <code>IMyShipController</code>, if found.</p><h3 id="construct-auto-syncing" tabindex="-1"><a class="header-anchor" href="#construct-auto-syncing"><span>Construct auto-syncing</span></a></h3><p>The <code>IntergridMessageService</code> and <code>CommandBus</code> have been updated to automatically sync with local instances of Mother Core and share command libraries. This means that any Mother-script can call commands of another without any additional effort from the player. Just load the script into a new programmable block and the scripts will handshake during boot using a <code>ConstructPing()</code>.</p><h3 id="merge-block-support" tabindex="-1"><a class="header-anchor" href="#merge-block-support"><span>Merge Block support</span></a></h3><p>The <code>BlockCatalogue</code> will now automatically update when merge blocks are merged/unmerged which means that Mother should work as expected before and after a merge. This also applies to attaching/detaching mechanical blocks (Rotor, Hinge, Piston).</p><h3 id="⚠️change-to-display-rendering" tabindex="-1"><a class="header-anchor" href="#⚠️change-to-display-rendering"><span>⚠️Change to Display Rendering</span></a></h3><p>In order to support a wider scope of compatibility, all Mother Core scripts will now target displays and surfaces differently. This new methodology enables rich display targeting and formatting, best demonstrated with <a href="#mother-gui-v01">Mother GUI</a>.</p><p><strong>OLD Method - Change Block Name</strong></p><p>Add <code>MMAP</code>, <code>MALMANAC</code>, etc. to the block&#39;s name. We also optionally supported cockpit/nested displays - <code>MLOG:1</code>. The problem is, what if I want <code>MMAP:2</code> as well? This makes names very verbose and, in my opinion, is the wrong approach.</p><p><strong>New Method - Use Custom Data</strong></p><p>Shifting closer to Mother&#39;s default configuration approach, we now set up our displays using their custom data. Not only does this allow for us to target multiple screens, but it allows multiple scripts to target multiple different screens simultaneously.</p><p><strong>Example - Display/Cockpit Custom Data</strong></p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#D4D4D4;">[surfaces]</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; print main menu (rendered by Mother GUI from player config)</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">0</span><span style="color:#D4D4D4;">=MainMenu</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; print map view (targeted from Mother Autopilot System script)</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">1</span><span style="color:#D4D4D4;">=MapView</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; print log using provided source script&#39;s name &quot;print the log of Mother OS script&quot;</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">2</span><span style="color:#D4D4D4;">=LogView </span><span style="color:#CE9178;">&quot;Mother OS&quot;</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><p>It&#39;s a bit more involved, but incredibly more flexible as more Mother Core scripts render to displays.</p><h3 id="important-commands" tabindex="-1"><a class="header-anchor" href="#important-commands"><span>Important Commands</span></a></h3><p>Commands can now be marked as <em>important</em> using the <code>!</code> prefix. Important commands take priority over local commands on other Mother Core instances on the same construct. This is useful when multiple instances define the same command but you want one instance to be the authoritative source. When Instance B runs <code>dock</code>, it will execute Instance A&#39;s important command instead of its own local command.</p><p><strong>Example - Programmable Block Custom Data (Instance A)</strong></p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#D4D4D4;">[commands]</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; This command will be called by all instances on the construct</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">!</span><span style="color:#569CD6;">dock</span><span style="color:#D4D4D4;">=connector/lock DockingPort</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><p><strong>Example - Programmable Block Custom Data (Instance B)</strong></p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#D4D4D4;">[commands]</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; This local command will be ignored in favor of Instance A&#39;s important command</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">dock</span><span style="color:#D4D4D4;">=echo </span><span style="color:#CE9178;">&quot;Local dock command&quot;</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><p>Use the <code>!!</code> prefix when running a command to force local execution, bypassing any important commands defined on other instances.</p><p><strong>Example - Execute in Terminal</strong></p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-bash"><code><span class="line"><span class="line"><span style="color:#6A9955;"># Run the important command from another instance (default behavior)</span></span></span>
<span class="line"><span class="line"><span style="color:#DCDCAA;">dock</span></span></span>
<span class="line"><span class="line"></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;"># Force run the local command, ignoring important commands</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">!!</span><span style="color:#DCDCAA;">dock</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h3 id="improved-displaymodule" tabindex="-1"><a class="header-anchor" href="#improved-displaymodule"><span>improved <code>DisplayModule</code></span></a></h3><p>The <code>DisplayModule</code> from Mother OS has moved most capability to Core so that scripts can use some of Mother&#39;s foundational logic for rendering content to a screen or the terminal window. Map logic has been moved to the <a href="#mother-autopilot-system---maps-v01">Mother Autopilot System (MAPS)</a> script.</p><h3 id="improved-colorhelper-utility" tabindex="-1"><a class="header-anchor" href="#improved-colorhelper-utility"><span>Improved <code>ColorHelper</code> Utility</span></a></h3><p>The <code>ColorHelper</code> utility class now supports hexadecimal color values.</p><h3 id="other-improvements" tabindex="-1"><a class="header-anchor" href="#other-improvements"><span>Other Improvements</span></a></h3><ul><li><code>BaseModuleCommand</code> now includes <code>IsSharedMode()</code> and <code>GetDistributedValue()</code> helper methods to support distributing values across multiple blocks. This enables commands to implement a <code>--share</code> flag for cumulative operations.</li><li>Add <code>MechanicalBlockModule</code> to handle mechanical block state changes.</li><li>Add <code>rename</code> command to set the grid&#39;s custom name. Use the <code>--unique</code> option to append a random integer for uniqueness.</li><li><code>Almanac</code> now tracks grid orientation (<code>Forward</code> and <code>Up</code> vectors) for improved navigation and docking operations. These are shared automatically in message headers.</li><li><code>Almanac</code> now validates records on load and periodically removes stale grid records that haven&#39;t pinged within 5 minutes.</li><li><code>AlmanacRecord</code> now includes <code>SafeRadius</code>, <code>UnicastId</code>, and orientation data (<code>Forward</code>, <code>Up</code>) for enhanced grid tracking.</li><li><code>IntergridMessageService</code> now elects a relay instance per construct for external communication and syncs commands across construct instances.</li><li><code>IntergridMessageService</code> now supports Almanac synchronization via the <code>almanac</code> route to share data across instances.</li><li><code>CommandBus</code> now maintains registries for <code>ConstructCommands</code> and <code>ImportantConstructCommands</code> to track commands available on other Mother Core instances.</li><li><code>CommandBus</code> now handles external command requests via relay and internal construct commands directly via <code>localcmd</code> route.</li><li>Task Queue in <code>CommandBus</code> is now a <code>List</code>.</li><li>Changes to the Programmable Block custom data no longer force a system reboot. Instead, modules should listen for the <code>SystemConfigUpdatedEvent</code> so that when the system configuration changes, the modules can update their internal configuration without needing to reboot the system.</li><li>Fixed issue where Almanac was not updating grid name and cannot be targeted when changing the name. When a grid&#39;s name changes, it will now be broadcasted on the construct, and through defined channels.</li><li>Fixed issue with setting hooks on the programmable block instance for blocks on the grid. Hooks for blocks can now be defined in the programmable block&#39;s custom data and are updated automatically.</li><li>Remove <code>FlightPlanningModule</code>, <code>FlightControlModule</code>, and <code>DockingModule</code>. These modules have been moved to the <a href="#mother-autopilot-system---maps-v01">Mother Autopilot System (MAPS)</a> script.</li></ul><h2 id="mother-autopilot-system-maps-v0-1" tabindex="-1"><a class="header-anchor" href="#mother-autopilot-system-maps-v0-1"><span>Mother Autopilot System - MAPS (v0.1)</span></a></h2><p>Mother Autopilot System is a fully independent script containing all flight planning and autopilot-related logic originally contained in Mother OS. To ensure the same gameplay experience, players should use Mother OS and MAPS so that they may access a wide command library in cooperation with autopilot features.</p><p>I intend to put a lot of focus into MAPS moving forward to ensure it is a competitive and feature-rich addition to the Space Engineers autopilot ecosystem.</p><p>There are a few areas that have changed which will need attention:</p><h3 id="map-and-almanac-display-rendering" tabindex="-1"><a class="header-anchor" href="#map-and-almanac-display-rendering"><span>Map and Almanac Display Rendering</span></a></h3><p>Mother Core 1.1 reworks how screens are targeted. In order to show the Map and Almanac screens, we now use custom data configuration on the screen/block.</p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#6A9955;">;standard LCD panel (only has one surface at index 0)</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">[surfaces]</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">0</span><span style="color:#D4D4D4;">=MapView</span></span></span>
<span class="line"><span class="line"></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; cockpit (where we have multiple surfaces)</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">[surfaces]</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">0</span><span style="color:#D4D4D4;">=LogView </span><span style="color:#CE9178;">&quot;Mother GUI&quot;</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">1</span><span style="color:#D4D4D4;">=MapView</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">2</span><span style="color:#D4D4D4;">=AlmanacView</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><p>This surface targeting paradigm makes Mother Core extremely flexible and powerful when rendering views to displays.</p><h2 id="mother-gui-v0-1" tabindex="-1"><a class="header-anchor" href="#mother-gui-v0-1"><span>Mother GUI (v0.1)</span></a></h2><p>Mother GUI is a brand new entry to the Mother Project. It is designed to render visualizations using Mother Core tools, but also demonstrates the cooperation between an execution-based script (Mother OS) and a player-interface and visualization script (Mother GUI). Both are built with Mother Core and so interoperate seamlessly from the player&#39;s perspective.</p><p><img src="`+o+'" alt="mother-gui1"><img src="'+i+'" alt="mother-gui2"><img src="'+t+`" alt="mother-gui3"></p><p>Here is what you need to know to get started.</p><h3 id="core-concepts" tabindex="-1"><a class="header-anchor" href="#core-concepts"><span>Core Concepts</span></a></h3><table><thead><tr><th>Concept</th><th>Description</th></tr></thead><tbody><tr><td>Display</td><td>Any LCD Panel, cockpit screen, or other text surface configured with type=gui in its Custom Data.</td></tr><tr><td>View</td><td>A named renderer that draws content onto a display (e.g. RotorView, PistonView, a menu).</td></tr><tr><td>Menu</td><td>A hierarchical list of items defined in the PB&#39;s Custom Data. A menu is just a special kind of view.</td></tr><tr><td>Command</td><td>A string run via the PB&#39;s argument input (e.g. from a button, timer, or hotbar action).</td></tr></tbody></table><h3 id="setting-up-a-display" tabindex="-1"><a class="header-anchor" href="#setting-up-a-display"><span>Setting Up a Display</span></a></h3><h4 id="configure-the-surface" tabindex="-1"><a class="header-anchor" href="#configure-the-surface"><span>Configure the Surface</span></a></h4><p>In the Custom Data of any LCD panel or cockpit, add a [surfaces] section to tell Mother GUI which view to show on which surface index. For an LCD panel with only one surface, we will use the 0<sup>th</sup> index (first screen).</p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#D4D4D4;">[surfaces]</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">0</span><span style="color:#D4D4D4;">=RotorView </span><span style="color:#CE9178;">&quot;MainRotor&quot;</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><p>The RotorView shows basic states and a visualization of the rotor&#39;s state in real time. We use the rotor&#39;s name as the first argument so that the RotorView renders the correct rotor data.</p><p>For cockpits or blocks with multiple screens:</p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#D4D4D4;">[surfaces]</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">0</span><span style="color:#D4D4D4;">=MainMenu</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">1</span><span style="color:#D4D4D4;">=RotorView </span><span style="color:#CE9178;">&quot;Landing Gear Rotor&quot;</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">2</span><span style="color:#D4D4D4;">=PistonView LiftPiston</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h4 id="optional-format-settings" tabindex="-1"><a class="header-anchor" href="#optional-format-settings"><span>Optional Format Settings</span></a></h4><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#D4D4D4;">[general]</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; adjust the size of the text</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">size</span><span style="color:#D4D4D4;">=0.6</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; adjust the entire screen using a scaling multiplier</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">scale</span><span style="color:#D4D4D4;">=1.2</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h3 id="setting-up-menus" tabindex="-1"><a class="header-anchor" href="#setting-up-menus"><span>Setting Up Menus</span></a></h3><p>Menus are a powerful feature built into Mother GUI and take inspiration from other scripts to enable a menu-navigation system. We can run commands and routines from these menus, as well as nest them to build rich interfaces for interacting with your grid.</p><p>Menus are defined in the PB&#39;s Custom Data using [menu:name] sections. Items use leading dots to express hierarchy (one dot per level of depth). Every line must include = to be INI-compatible. You can use an empty value for submenus.</p><p>Let&#39;s define our <code>MainMenu</code>:</p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#D4D4D4;">[menu:Main Menu]</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; Define simple command</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">Startup</span><span style="color:#D4D4D4;">=battery/auto MainBatteries</span><span style="color:#6A9955;">; block/on #atmo-thrusters;</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; Define a Lights submenu</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">Lights</span><span style="color:#D4D4D4;">=</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">.Toggle Light </span><span style="color:#569CD6;">1</span><span style="color:#D4D4D4;">= block/toggle Light1</span><span style="color:#6A9955;">;</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">.Toggle Light </span><span style="color:#569CD6;">2</span><span style="color:#D4D4D4;">= block/toggle Light2</span><span style="color:#6A9955;">;</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; define a reboot action</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">Reboot</span><span style="color:#D4D4D4;">=boot</span><span style="color:#6A9955;">;</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><p>In the above example, the player will see:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-text"><code><span class="line"><span class="line"><span style="color:#D4D4D4;">Main Menu      ⚬</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">----------------</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">&gt; Startup</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">  Lights       &gt;</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">  Reboot</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;"></span></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><p>If they select the <code>Lights</code> option, the nested submenu will open:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-text"><code><span class="line"><span class="line"><span style="color:#D4D4D4;">Lights         ⚬</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">----------------</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">&gt; Toggle Light 1</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">  Toggle Light 2</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">  &lt;&lt; Back</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;"></span></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><p>Let&#39;s go even further and define a <code>Lights Menu</code> menu that we can navigate to:</p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#6A9955;">; The new menu</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">[menu:Lights Menu]</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">Toggle Light </span><span style="color:#569CD6;">1</span><span style="color:#D4D4D4;">= block/toggle Light1</span><span style="color:#6A9955;">;</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">Toggle Light </span><span style="color:#569CD6;">2</span><span style="color:#D4D4D4;">= block/toggle Light2</span><span style="color:#6A9955;">;</span></span></span>
<span class="line"><span class="line"></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">[menu:Main Menu]</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; Define simple command</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">Startup</span><span style="color:#D4D4D4;">=battery/auto MainBatteries</span><span style="color:#6A9955;">; block/on #atmo-thrusters;</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; navigate to the Lights Menu</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">Lights</span><span style="color:#D4D4D4;">=view/go self </span><span style="color:#CE9178;">&quot;Lights Menu&quot;</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; define a reboot action</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">Reboot</span><span style="color:#D4D4D4;">=boot</span><span style="color:#6A9955;">;</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><p>Breaking up menus allows you to keep functionality modular. Remember to use the <code>self</code>keyword so the navigate know to target the screen you have run the <code>select</code> action for.</p><h4 id="duplicate-label-disambiguation" tabindex="-1"><a class="header-anchor" href="#duplicate-label-disambiguation"><span>Duplicate label disambiguation</span></a></h4><p><code>MyIni</code> requires unique keys within a section. Prefix duplicate labels with a number and colon — the prefix is stripped from the display label:</p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#D4D4D4;">[menu:main]</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">Lights</span><span style="color:#D4D4D4;">=</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; Define Light1 menu</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">.</span><span style="color:#569CD6;">Light1</span><span style="color:#D4D4D4;">=</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">..0:</span><span style="color:#569CD6;">Toggle</span><span style="color:#D4D4D4;">= block/toggle Light1</span><span style="color:#6A9955;">;</span></span></span>
<span class="line"><span class="line"></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">.</span><span style="color:#569CD6;">Light2</span><span style="color:#D4D4D4;">=</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">..1:</span><span style="color:#569CD6;">Toggle</span><span style="color:#D4D4D4;">= block/toggle Light2</span><span style="color:#6A9955;">;</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><p>Without unique IDs, MyIni would discover two <code>Toggle</code> keys and throw an error. This only applies to a simple menu, though, so we can nest additional menus to get around this problem.</p><h3 id="built-in-views" tabindex="-1"><a class="header-anchor" href="#built-in-views"><span>Built-In Views</span></a></h3><p>⚠️These are subject to change as Mother GUI evolves. Please let me know what&#39;s missing, or how you&#39;d improve these.</p><h4 id="rotorview" tabindex="-1"><a class="header-anchor" href="#rotorview"><span>RotorView</span></a></h4><p>Displays rotor diagnostics: name, lock state, torque, braking torque, and a live angle dial.</p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#6A9955;">; navigate to the RotorView on the BridgeLCD</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">view/go BridgeLCD RotorView </span><span style="color:#CE9178;">&quot;Turret Rotor&quot;</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h4 id="hingeview" tabindex="-1"><a class="header-anchor" href="#hingeview"><span>HingeView</span></a></h4><p>Displays hinge diagnostics: lock state, torque, braking torque, and a live semi-circle angle dial (−90° to +90°).</p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#6A9955;">; navigate to the HingeView on the BridgeLCD</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">view/go BridgeLCD HingeView </span><span style="color:#CE9178;">&quot;LandingGearHinge1&quot;</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h4 id="pistonview" tabindex="-1"><a class="header-anchor" href="#pistonview"><span>PistonView</span></a></h4><p>Displays piston diagnostics: status (extending/retracting/stopped), velocity, and a horizontal progress bar showing current extension within min/max limits.</p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#6A9955;">; navigate to the PistonView on the BridgeLCD</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">view/go BridgeLCD PistonView LiftPiston</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h3 id="widescreen-split-views" tabindex="-1"><a class="header-anchor" href="#widescreen-split-views"><span>Widescreen / Split-views</span></a></h3><p>On widescreen displays, the script automatically splits the viewport in two:</p><ul><li>Left half — the active menu.</li><li>Right half — a side-panel view (pushed via view/go on a widescreen display).</li></ul><h3 id="navigation-commands" tabindex="-1"><a class="header-anchor" href="#navigation-commands"><span>Navigation Commands</span></a></h3><p>Wire these to button panels, timers, or hotbar actions via the PB&#39;s argument field.</p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#D4D4D4;">view/select </span><span style="color:#CE9178;">&quot;Display Name&quot;</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">view/back   </span><span style="color:#CE9178;">&quot;Display Name&quot;</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">view/up </span><span style="color:#CE9178;">&quot;Display Name&quot;</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">view/down </span><span style="color:#CE9178;">&quot;Display Name&quot;</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">view/go </span><span style="color:#CE9178;">&quot;Display Name&quot;</span><span style="color:#D4D4D4;"> [NewViewOrMenuName] [ViewParameters...]</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h4 id="cockpit-and-multi-screen-traversal" tabindex="-1"><a class="header-anchor" href="#cockpit-and-multi-screen-traversal"><span>Cockpit and multi-screen traversal</span></a></h4><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#6A9955;">; Plain LCD panel</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">view/go BridgeLCD RotorView </span><span style="color:#CE9178;">&quot;Turret Rotor&quot;</span></span></span>
<span class="line"><span class="line"></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; Cockpit surface 0 (front-facing screen)</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">view/go </span><span style="color:#CE9178;">&quot;Fighter Cockpit:0&quot;</span><span style="color:#D4D4D4;"> MainMenu</span></span></span>
<span class="line"><span class="line"></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; Cockpit surface 1 (side screen) — pinned to a specific rotor</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">view/go </span><span style="color:#CE9178;">&quot;Fighter Cockpit:1&quot;</span><span style="color:#D4D4D4;"> RotorView </span><span style="color:#CE9178;">&quot;Turret Rotor&quot;</span></span></span>
<span class="line"><span class="line"></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; Cockpit surface 2 — piston diagnostics</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">view/go </span><span style="color:#CE9178;">&quot;Fighter Cockpit:2&quot;</span><span style="color:#D4D4D4;"> PistonView </span><span style="color:#CE9178;">&quot;Cargo Lift&quot;</span></span></span>
<span class="line"><span class="line"></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; Navigate to a different view on surface 0</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">view/go </span><span style="color:#CE9178;">&quot;Fighter Cockpit:0&quot;</span><span style="color:#D4D4D4;"> HingeView LandingGearHinge</span></span></span>
<span class="line"><span class="line"></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; Tag-based targeting (# prefix) with surface index</span></span></span>
<span class="line"><span class="line"><span style="color:#D4D4D4;">view/go </span><span style="color:#6A9955;">#cockpit:0 HingeView LandingGearHinge</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><h4 id="self-keyword" tabindex="-1"><a class="header-anchor" href="#self-keyword"><span><code>self</code> keyword</span></a></h4><p>Inside a menu command string, use self instead of a display name to refer to the display that triggered the command — works with both plain names and surface-indexed displays:</p><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre class="shiki dark-plus" style="background-color:#1E1E1E;" tabindex="0 language-ini"><code><span class="line"><span class="line"><span style="color:#D4D4D4;">[menu:main]</span></span></span>
<span class="line"><span class="line"><span style="color:#6A9955;">; Navigates whichever screen this menu is shown on</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">Rotor</span><span style="color:#D4D4D4;">=view/go self </span><span style="color:#CE9178;">&quot;RotorView&quot;</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">&quot;Turret Rotor&quot;</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">Piston</span><span style="color:#D4D4D4;">=view/go self </span><span style="color:#CE9178;">&quot;PistonView&quot;</span><span style="color:#D4D4D4;"> </span><span style="color:#CE9178;">&quot;Cargo Lift&quot;</span></span></span>
<span class="line"><span class="line"><span style="color:#569CD6;">Back</span><span style="color:#D4D4D4;">=view/back self</span></span></span>
<span class="line"><span class="line"></span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"></div></div><p>This means the same menu definition works correctly whether it is displayed on &quot;Bridge LCD&quot;, &quot;Cockpit:0&quot;, or &quot;Cockpit:2&quot; without any changes.</p><h3 id="quick-start-guide" tabindex="-1"><a class="header-anchor" href="#quick-start-guide"><span>Quick Start Guide</span></a></h3><ol><li>Place and configure the <code>Mother GUI</code> PB.</li><li>Add a [menu:MainMenu] section to the PB&#39;s Custom Data with your desired items.</li><li>Open each LCD/cockpit screen and add a [surfaces] section pointing to your menu or a specific view.</li><li>Wire navigation buttons/actions to the PB: <ul><li><code>view/up &quot;Cockpit:0</code></li><li><code>view/down &quot;Cockpit:0</code></li><li><code>view/select &quot;Cockpit:0</code></li><li><code>view/back &quot;Cockpit:0</code></li></ul></li></ol><h3 id="tips-and-gotchas" tabindex="-1"><a class="header-anchor" href="#tips-and-gotchas"><span>Tips and Gotchas</span></a></h3><ul><li>Every line in a [menu:*] section must contain an equals sign <code>=</code>. MyIni drops lines without it. Use <code>[Label]=</code> for group headers (e.g. <code>Rotors=</code>).</li><li>Surface indices on cockpit screens start at 0. Use &quot;BlockName:1&quot; to target the second screen, &quot;BlockName:2&quot; for the third, and so on.</li><li>When multiple cockpit screens share the same button panel, use self in command strings so a single button wiring works for all of them regardless of surface index.</li><li>Mechanical block views (RotorView, HingeView, PistonView) refresh every program cycle while visible, so angles and positions always stay current.</li><li>Custom Data changes to any display block are detected at runtime and trigger automatic re-discovery. No PB recompile or boot needed.</li></ul><h2 id="mother-cli-v1-0-3" tabindex="-1"><a class="header-anchor" href="#mother-cli-v1-0-3"><span>Mother CLI (v1.0.3)</span></a></h2><p>WORK IN PROGRESS</p><ol><li>Support targeting of specific Mother Core version</li></ol><h2 id="mother-dev-tools-v0-2" tabindex="-1"><a class="header-anchor" href="#mother-dev-tools-v0-2"><span>Mother Dev Tools (v0.2)</span></a></h2><ol><li>Update command grammar to support new commands and hooks.</li></ol>`,191)])])}const h=a(p,[["render",r]]),u=JSON.parse('{"path":"/ClosedTestingGroup/Releases/MotherProject-1_1/beta-testing-group-instructions.html","title":"Mother 1.1 Release","lang":"en-US","frontmatter":{},"git":{"updatedTime":1777772886000,"contributors":[{"name":"lukejamesmorrison","username":"lukejamesmorrison","email":"30843159+lukejamesmorrison@users.noreply.github.com","commits":5,"url":"https://github.com/lukejamesmorrison"},{"name":"Copilot","username":"Copilot","email":"copilot@github.com","commits":1,"url":"https://github.com/Copilot"}],"changelog":[{"hash":"7ceefa1f8051fc01db755872152bac6195f77e1e","time":1777772886000,"email":"30843159+lukejamesmorrison@users.noreply.github.com","author":"Luke","message":"add rotor,hinge,piston limit commands to docs"},{"hash":"db7530af7c3ec62794ea4e1f6308da33c48197ae","time":1777654735000,"email":"30843159+lukejamesmorrison@users.noreply.github.com","author":"Luke","message":"beta testing group updates"},{"hash":"e393e07c395c19a3b89332c47820220e21a4cb74","time":1777338511000,"email":"30843159+lukejamesmorrison@users.noreply.github.com","author":"Luke","message":"Update beta testing group instructions"},{"hash":"90a12c913196138fb57c4bd7d6d212fb86e0ed7d","time":1777312117000,"email":"30843159+lukejamesmorrison@users.noreply.github.com","author":"Luke","message":"Improve language of beta testing group instructions","coAuthors":[{"name":"Copilot","email":"copilot@github.com"}]},{"hash":"3d5caf90f433cc69115fe5294d814a8b67b1acc0","time":1777311644000,"email":"30843159+lukejamesmorrison@users.noreply.github.com","author":"Luke","message":"Add beta testing group area"}]},"filePathRelative":"ClosedTestingGroup/Releases/MotherProject-1_1/beta-testing-group-instructions.md"}');export{h as comp,u as data};
